  "113_civil_34": {
    "options": {
      "A": {
        "label": "",
        "reason": "輕度失智症者在法律上並未當然喪失行為能力，須視其為意思表示時是否處於無意識狀態而定。"
      },
      "B": {
        "label": "",
        "reason": "民法第74條之暴利行為（急迫、輕率、無經驗），係以「顯失公平之財產給付或約定」為要件，且法律效果為得聲請法院撤銷或減輕給付，非一律無效。"
      },
      "C": {
        "label": "",
        "reason": "依民法第75條後段規定：「雖非無行為能力人，而其意思表示，係在無意識或精神錯亂中所為者亦同（無效）。」本題明定乙利用甲「意識模糊（無意識）」之際訂約，故該贈與（債權行為）及移轉登記（物權行為）依法均為無效。"
      },
      "D": {
        "label": "",
        "reason": "單純動機不純不必然導致契約因違反公序良俗而無效，仍應以民法第75條意思能力欠缺為本案直接、核心之法律效果。"
      }
    },
    "concept": "行為人於無意識或精神錯亂中所為之意思表示（包括債權與物權行為）一律無效。",
    "law_basis": "",
    "supplement": ""
  },
