  "112_civil_7": {
    "options": {
      "A": {
        "label": "",
        "reason": "本借款債權之時效依民法第125條為 15 年；而保證債權本於保證契約，其時效亦為 15 年。"
      },
      "B": {
        "label": "",
        "reason": "清償期為 102 年 5 月 1 日，時效於 117 年 5 月 1 日即已屆滿。乙於 117 年 6 月 1 日起訴時，主債務（借款債權）已罹於消滅時效。依民法第742條第1項規定：「主債務人所有之抗辯，保證人得主張之。」丙自得援引主債務之時效消滅抗辯，拒絕履行保證責任。"
      },
      "C": {
        "label": "",
        "reason": "連帶保證人拋棄的是「先訴抗辯權」（民法第745條、第746條本文），但依民法第739條之1規定，本節所規定保證人之權利（包括第742條之主債務人抗辯權）不得預先拋棄。"
      },
      "D": {
        "label": "",
        "reason": "雖然乙對丙之保證債權若從 117 年起算可能尚未因起訴而中斷逾期（因時效自中斷事由終止重行起算），但因保證債務具從屬性，只要主債務時效完成，保證人即可行使抗辯權拒絕給付（民法第742條第1項）。"
      }
    },
    "concept": "保證人（含連帶保證人）得主張主債務人之時效消滅抗辯權以拒絕給付。",
    "law_basis": "",
    "supplement": ""
  },
