  "114_commercial_27": {
    "options": {
      "A": {
        "label": "",
        "reason": "依票據法第136條規定，付款人（銀行）於提示期限經過後，仍「得」為付款。故銀行若選擇予以付款，並無不可。"
      },
      "B": {
        "label": "",
        "reason": "依票據法第136條之反面解釋，提示期限經過後，銀行雖「得」付款，但並「無付款之義務」。尤其在存款不足（僅1/5）且發票人未資助之情況下，銀行亦「可不予付款」。"
      },
      "C": {
        "label": "",
        "reason": "依票據法第135條規定，發票人於提示期限經過後，得撤銷付款之委託。本題提示期限已過3個月，甲依法「得」撤銷付款之委託。"
      },
      "D": {
        "label": "",
        "reason": "本題選此）：依票據法第137條第1項及第2項規定，付款人存款不足時，得僅就不敷之數「拒絕一部付款」，執票人「不得拒絕一部付款」。且票據法並無規定銀行「必須先幫發票人墊付全額」之義務，銀行僅就甲現有之1/5資金為一部付款即可。"
      }
    },
    "concept": "支票期後提示之效力、付款委託之撤銷與一部付款。",
    "law_basis": "票據法第 135 條",
    "supplement": ""
  },
