      "C": {
        "label": "",
        "reason": "原住民族委員會：屬中央行政主體，非A直轄市，不適用。"
      },
      "D": {
        "label": "",
        "reason": "A直轄市山地原住民區之區公所：原住民區為地方自治團體，與直轄市為不同行政主體（地方制度法第83條之2），不適用。"
      }
